const Q_BIOLOGY_2012=[{"id": "objective>Biology>2012>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">History</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject of these questions is Biology. This can be determined from the context of the questions, which are all related to biological concepts and phenomena.</div>", "topic": "BIOLOGY"}, {"id": "objective>Biology>2012>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The organelle responsible for heredity is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The organelle responsible for heredity is labelled II.The organ labelled is nucleus.it is responsible for heredity </div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2012>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labeled IV is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mitochondrion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endoplasmic reticulum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labeled IV in the digram is the Endoplasmic reticulum.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2012>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is most advanced in the evolutionary trend of animals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Liverfluke</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Earthworm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Snail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cockroach</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the evolutionary trend of animals, the cockroach is the most advanced. This is because it belongs to the class Insecta, which is higher in the animal kingdom hierarchy than the classes of the other options. Liverfluke belongs to the class Trematoda, earthworm to the class Oligochaeta, and snail to the class Gastropoda. Insects are more complex and have more advanced features such as a highly developed nervous system and the ability to fly.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2012>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the lowest category of classification?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Class</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Family</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Genus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the biological classification system, species is the lowest category. This system, also known as the Linnaean system, classifies living organisms into a hierarchy of taxonomic ranks. From highest to lowest, these ranks are: Domain, Kingdom, Phylum, Class, Order, Family, Genus, and Species. Therefore, species is the lowest category of classification.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2012>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants that show secondary growth are usually found among the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thallophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pteridophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monocotyledons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dicotyledons</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary growth, which involves the thickening of the plant body, is usually found among the dicotyledons. This is because dicotyledons have a vascular cambium, a type of meristematic tissue that contributes to secondary growth. Thallophytes, pteridophytes, and monocotyledons typically do not show secondary growth.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2012>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fungi are a distinct group of eukaryotes mainly because they have</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no chlorophyll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many fruiting bodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sexual and asexual reproduction.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fungi are a distinct group of eukaryotes mainly because they lack chlorophyll. Chlorophyll is the pigment that gives plants their green color and is used in photosynthesis to convert light energy into chemical energy. Fungi, unlike plants, do not perform photosynthesis and therefore do not have chlorophyll. While fungi do produce spores, have many fruiting bodies, and can reproduce both sexually and asexually, these characteristics are not unique to fungi and are shared by other groups of organisms.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>2012>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An arthropod that is destructive at the early stage of its life cycle is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">butterfly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">millipede</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Butterfly is the arthropod that is destructive at the early stage. </div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2012>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An animal body that can be cut along its axis in any plane to give two identical parts is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">radially symmetrical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bilaterally symmetrical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">asymmetrical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">symmetrical</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An animal body that can be cut along its axis in any plane to give two identical parts is said to be radially symmetrical. This means that the animal's body has a symmetry around a central axis, similar to the spokes on a wheel. Examples of animals with radial symmetry include starfish and jellyfish. Bilateral symmetry, on the other hand, means that an animal can be divided into mirror-image halves only along one plane, which is typically the midline. Asymmetrical animals cannot be divided into mirror-image halves along any plane, and symmetrical is a general term that could refer to either radial or bilateral symmetry.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2012>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following possesses mammary gland?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dogfish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Whale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Catfish</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mammary glands are the organs that produce milk for the sustenance of a newborn. These are characteristic of mammals, including whales. Dogfish, sharks, and catfish are types of fish, and fish do not possess mammary glands.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2012>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The feature that links birds to reptiles in evolution is the possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">feathers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beak</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skeleton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scales</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds and reptiles are linked in evolution by the possession of scales. While birds are covered in feathers, they have scales on their feet and legs. Reptiles are covered in scales. Feathers, beaks, and skeletons are not unique to both birds and reptiles.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2012>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Counter-shading is an adaptive feature that enables animals to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fight enemies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain undetected</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warn enemies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attract mates</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Counter-shading is a form of camouflage that animals use to remain undetected. It involves having a darker color on the top side and a lighter color on the underside. This makes the animal harder to see from both above and below, helping it avoid predators.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2012>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following plant structures lacks a waterproof cuticle?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Leaf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Root</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shoot</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The root of a plant lacks a waterproof cuticle. The cuticle is a waxy, water-repelling layer found on the epidermal cells of leaves and stems but not roots. It helps to prevent water loss from the plant. Roots, on the other hand, are designed to absorb water and therefore do not have this waterproof layer.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2012>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the mammalian male reproductive system, the part that serves as a passage for both urine and semen is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">urethra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ureter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bladder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seminal vesicle</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The urethra in the male reproductive system serves as a passage for both urine and semen. The urethra runs through the penis and carries semen as well as urine out of the body. The ureter is a tube that carries urine from the kidney to the bladder, the bladder stores urine until it is released, and the seminal vesicle produces a significant portion of the fluid that makes up semen.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2012>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, which of the following is required in minute quantities for <br/> growth?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potassium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phosphorus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper is required in minute quantities for plant growth. It is a micronutrient that plays a number of important roles in plants, including enzyme activation and photosynthesis. Potassium, phosphorus, and sodium, on the other hand, are macronutrients, which are required by plants in larger amounts.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>2012>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms is both parasitic and autotrophic?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sundew</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Loranthus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizopus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tapeworm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Loranthus is a type of parasitic plant that is also capable of photosynthesis, making it both parasitic and autotrophic. Parasitism is a relationship between species, where one organism, the parasite, lives on or in another organism, the host, causing it some harm. Autotrophs are organisms that can produce their own food from the substances available in their surroundings using light (photosynthesis) or chemical energy (chemosynthesis).</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2012>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A function of hydrochloric acid produced in the human stomach during digestion is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">neutralize the effect of bile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coagulate milk protein and emulsify fats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stop the action of ptyalin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">break up food into smaller particles.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrochloric acid in the stomach stops the action of ptyalin. Ptyalin is an enzyme in saliva that breaks down starch into maltose. When the food reaches the stomach, the acidic environment inactivates the ptyalin, stopping further breakdown of the starch.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2012>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a polysaccharide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sucrose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maltose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cellulose</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cellulose is a polysaccharide. Polysaccharides are carbohydrates with high molecular weight made up of long chains of monosaccharide units bound together by glycosidic linkages. Cellulose is a complex carbohydrate, or polysaccharide, consisting of 3,000 or more glucose units. The other options, Glucose, Sucrose, and Maltose, are all simple sugars or disaccharides, not polysaccharides.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2012>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Transportation in the xylem is represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IV, the xylem transport or conducts water from the root to other parts of the plant.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2012>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The arrow labeled II represents the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">release of oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intake of carbon(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">movement of photosynthate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">movements of nutrients</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">II is the release of a by-product of photosynthesis. This by-product is Oxygen. Also the arrow on the diagram shows that II is released not taken in. <br/>  <br/> III is the intake of a gas needed for photosynthesis. This gas is carbon (IV)oxide. </div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2012>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the kidney of animals, the site of ultra-filtration is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">uriniferous tubule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bowman's capsule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loop of Henle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">renal tubule</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the kidney of animals, the site of ultra-filtration is the Bowman's capsule. Ultra-filtration is the process by which blood is filtered in the kidneys to remove waste products and excess substances. This process occurs in the Bowman's capsule, which is a cup-like sac at the beginning of the tubular component of a nephron in the mammalian kidney that performs the first step in the filtration of blood to form urine.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2012>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is involved in secondary thickening in plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Collenchyma and xylem cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vascular cambium and collenchyma cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vascular cambium and cork cambium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cork cambium and sclerenchyma</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary thickening in plants involves the Vascular cambium and cork cambium. Secondary thickening is the process by which stems and roots of plants increase in thickness. This is achieved through the activity of the vascular cambium, which produces secondary xylem and phloem, and the cork cambium, which produces the protective outer layer of the plant.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2012>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a fruit that develops from a single carpel is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">okro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tomato</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the fruit develops from a single carpel or fused carpels of a single ovary, it is known as a simple fruit as seen in nuts and beans.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2012>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The developing embryo is usually contained in the part labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part abelled II is known as the uterus or womb , the developing embrayo grows in the uterus </div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2012>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The function of the part labeled III is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">produce egg cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect sperms during fertilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secrete hormones during coitus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the developing embryo</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the part labeled III is to produce egg cells. Ovaries produces eggs</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2012>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plant growth can be artificially stimulated by the addition of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gibberellin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kinin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abscisic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethylene</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gibberellins are plant hormones that regulate growth and influence various developmental processes, including stem elongation, germination, dormancy, flowering, sex expression, enzyme induction, and leaf and fruit senescence. Therefore, plant growth can be artificially stimulated by the addition of gibberellin.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2012>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The autonomic nervous system consists of neurons that control the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">voluntary muscles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heart beat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tongue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hands</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The autonomic nervous system is a control system that acts largely unconsciously and regulates bodily functions such as the heart rate, digestion, respiratory rate, pupillary response, urination, and sexual arousal. Therefore, it controls the heartbeat.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2012>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants of temperate origin can be grown in tropical areas in the vegetation zones of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rain forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guinea savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sudan savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">montane forest</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Montane forests are found in cooler-climate mountainous areas. Because of the cooler climate, they are able to support plant species from temperate latitudes, which are not adapted to the heat and humidity of the tropics. Therefore, plants of temperate origin can be grown in tropical areas in the vegetation zones of the montane forest.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : HIGHLANDS OF MONTANE FORESTS AND GRASSLANDS"}, {"id": "objective>Biology>2012>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The water cycle is maintained mainly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evaporation of water in the environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation and condensation of water in the environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation of water in the environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transpiration and respiration in plants</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The water cycle is maintained mainly by both evaporation and condensation of water in the environment. Evaporation is the process by which water changes from a liquid to a gas or vapor. This is the primary path for water to move from the liquid state back to the water cycle as atmospheric water vapor. Condensation is the process by which water vapor in the air is changed into liquid water. Condensation is crucial to the water cycle because it is responsible for the formation of clouds. These clouds may produce precipitation, which is the primary route for water to return to the Earth's surface within the water cycle. </div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2012>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Organisms living in an estuarine habitat are adapted to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">withstand wide fluctuations in temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">survive only in water with low salinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">withstand wide fluctuations in salinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feed only on phytoplankton and dead organic matter</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Estuarine habitats are where rivers meet the sea and the water can vary from fresh to brackish to salt water. Organisms living in these habitats are adapted to withstand wide fluctuations in salinity. This is because the salinity of estuaries changes with the tides, and organisms living in these habitats need to be able to adapt to these changes. </div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2012>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of slit roots, pneumatophores, sunken stomata and salt glands are adaptive features of plants found in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tropical rainforest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mangrove swamps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grassland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">montane forest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of stilt roots, pneumatophores, sunken stomata, and salt glands are adaptive features of plants found in the mangrove swamps. Stilt roots provide support and stability to the plants in the soft muddy soil. Pneumatophores are specialized root structures that stick up out of the soil like snorkels, allowing the plant to breathe even when its main roots are submerged. Sunken stomata and salt glands help the plant to deal with the high salinity of the water in the mangrove swamps. So, the correct answer is option 2.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2012>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following animals can exist solely on the water they get from food <br/> and metabolic reactions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Forest arboreal dwellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Desert dwellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Forest ground dwellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rainforest dwellers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Desert dwellers, such as kangaroo rats, can survive without drinking water. They get the water they need from the food they eat and the metabolic reactions in their bodies. Metabolic water is water created inside a living organism through their metabolism, by oxidizing energy-containing substances in their food.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2012>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most likely first colonizers of a bare rock are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mosses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ferns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lichen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fungi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lichens are the most likely first colonizers of a bare rock. They are pioneer species, which are the first to colonize previously disrupted or damaged ecosystems, beginning a chain of ecological succession that ultimately leads to a more biodiverse steady-state ecosystem. Lichens can survive in harsh conditions and can start the process of soil formation by breaking down the rocks.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>2012>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The carrying capacity of a habitat is reached when the population growth begins to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase slowly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase exponentially</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slow down</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain steady</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The carrying capacity of a habitat is reached when the population growth begins to remain steady. Carrying capacity refers to the maximum number of individuals of a particular species that a particular environment can support. When the carrying capacity is reached, the population size becomes stable, and the growth rate is zero.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2012>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The abiotic factors that control human population include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disease and famine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">space and rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flooding and earthquake</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature and disease</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The abiotic factors that control human population include space and rainfall. Space refers to the physical environment and geographical location where a population resides. Rainfall affects the availability of water, which is essential for human survival and agriculture. Disease and famine, flooding and earthquake, and temperature and disease are biotic factors and natural disasters, not abiotic factors.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2012>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An indigenous method of renewing and maintaining soil fertility is by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clearing farms by burning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planting one crop type</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding inorganic fertilizers yearly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation and shifting cultivation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Crop rotation is the practice of growing different types of crops in the same area in sequenced seasons to help restore soil nutrients. Shifting cultivation, also known as slash and burn agriculture, is a method where an area of vegetation is cut down and burned before new seeds are sown.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>2012>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diseases caused by water-borne pathogens include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gonorrhea and poliomyelitis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">typhoid and syphilis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tuberculosis and cholera</div>", "<div style=\"font-family:Cambria;font-size:17px;\">typhoid and cholera</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both typhoid and cholera are diseases caused by bacteria that can be transmitted through contaminated water.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2012>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The graph illustrates</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the highest frequency for height of 2 metres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a discontinuously varying character</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a continuously varying character</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total yield in a cassava farm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The graph illustrates a continuously varying character.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2012>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The largest number of cassava plants has an approximate height of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.4m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.6m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The largest number of cassava plants has an approximate height of 1.6m(from the diagram).</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2012>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true in blood transfusion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A person of blood group AB can donate blood only to another person of blood group AB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Person of blood groups A and B can donate or receive blood from each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A person of blood group AB can receive blood only persons of blood group A or B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A person of blood group O can donate only to a person of blood group O</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A person of blood group AB is a universal recipient, meaning they can receive blood from any group (A, B, AB, or O), but they can only donate blood to individuals of the same group AB. This is because AB blood group individuals have both A and B antigens on their red blood cells, but their plasma does not contain any antibodies against A or B blood groups. Therefore, they can receive blood from any group without causing an immune response.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2012>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A yellow maize is planted and all the fruits obtained are of yellow seeds. When they are cross-bred, yellow seeds and white seeds are obtained in a ratio <br/> 3:1. The yellow seed is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">non-heritable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sex-linked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a recessive trait</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dominant trait</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Mendelian genetics, a dominant trait is one that is phenotypically expressed in heterozygotes. In the given scenario, the yellow seed color is dominant because it appears in the F1 generation after cross-breeding. The 3:1 ratio of yellow to white seeds in the F2 generation is a classic Mendelian ratio, indicating that yellow is the dominant trait and white is the recessive trait.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2012>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a colour-blind man marries a carrier woman. What is the probability <br/> of their offspring being colour blind?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Colour blindness is a sex-linked recessive trait. This means that a male offspring only needs to inherit one copy of the colour-blind gene from his mother to be colour blind. If a colour-blind man (XcY) marries a carrier woman (XXc), there is a 50% chance that a male offspring will inherit the colour-blind gene from his mother and be colour blind (XcY). The other 50% of the time, the male offspring will inherit the normal gene from his mother and will not be colour blind (XY).</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2012>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct base pairing for DNA is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adenine → thymine and guanine → cytosine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adenine → guanine and thymine → cytosine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adenine → cytosine andguanine → thymine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adenine → adenine and cytosine → cytosine</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In DNA, adenine (A) pairs with thymine (T) and guanine (G) pairs with cytosine (C). This is known as complementary base pairing and is a fundamental principle in the structure of DNA.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2012>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The type of interaction shown is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">interspecific competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intraspecific competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutualism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cooperation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Interspecific competition occurs between individuals of different species.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2012>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following statements is true of the interaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P. aurelia is better adapted for obtaining food than P.caudatum.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P. caudatum is better adapted for obtaining food than P. aurelia.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both organisms cannot co-exist.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both organisms cannot reproduce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P. aurelia is better adapted for obtaining food than P.caudatum.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2012>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short thick beak in birds is an adaptation for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crushing seeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sucking nectar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tearing flesh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">straining mud</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birds with short, thick beaks are typically adapted for crushing seeds. The shape and strength of the beak allow the bird to break open hard seed shells.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTIONS IN ORGANISMS"}, {"id": "objective>Biology>2012>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basking of agama lizards in the sun is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">change the colour of their body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raise their body temperature to become active</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fight to defend their territories</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attract the female for courtship</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basking of agama lizards in the sun is to raise their body temperature to become active. Agama lizards are ectothermic animals, which means they rely on external sources of heat to regulate their body temperature. Basking in the sun allows them to absorb heat and increase their body temperature, which enhances their metabolic activities and makes them more active.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2012>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The significance of a very large number of termites involved in nuptial swarming is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide birds with plenty of food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure their perpetuation despite predatory pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">search for a favourable place to breed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure that every individual gets a mate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The significance of a large number of termites involved in nuptial swarming is to ensure their perpetuation despite predatory pressure. Nuptial swarming is a reproductive strategy used by termites where a large number of winged termites (alates) leave their nest to mate and start new colonies. The large number of termites involved in this process ensures that even if many are eaten by predators, enough will survive to continue the species.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2012>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use and disuse of body parts and the inheritance of acquired traits were used to explain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Darwin's Theory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lamarck's Theory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">genetic drift</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gene flow</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The use and disuse of body parts and the inheritance of acquired traits were used to explain Lamarck's Theory. This theory, also known as Lamarckism, proposed that an organism can change during its lifetime in response to its environment, and those changes are passed on to its offspring. It is named after the French biologist Jean-Baptiste Lamarck, who incorporated the action of soft inheritance into his evolutionary theories.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2012>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From his study of Galapagos finches, Darwin derived his Theory of evolution from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">comparative anatomy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">comparative physiology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fossil remains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">comparative embryology</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From his study of Galapagos finches, Darwin derived his Theory of evolution from comparative anatomy.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}];
